"""Haiku-backed, source-grounded Forecasts prediction generation."""

from __future__ import annotations

import json
import math
import re
from dataclasses import dataclass
from datetime import datetime, timedelta, timezone
from decimal import Decimal
from enum import Enum
from pathlib import Path
from typing import Any

from noosphere.currents._llm_client import LLMResponse, make_client
from noosphere.currents.budget import BudgetExhausted
from noosphere.currents.opinion_generator import (
    _estimate_tokens,
    _extract_json_object,
    validate_citations,
)
from noosphere.forecasts.paper_bet_engine import PaperBetConfig, evaluate_and_stake
from noosphere.mitigations.prompt_separator import PromptSeparator
from noosphere.models import (
    ForecastCitation,
    ForecastMarketStatus,
    ForecastPrediction,
    ForecastPredictionStatus,
    ForecastSupportLabel,
    ForecastTrace,
)


class ForecastOutcome(str, Enum):
    PUBLISHED = "PUBLISHED"
    ABSTAINED_BUDGET = "ABSTAINED_BUDGET"
    ABSTAINED_INSUFFICIENT_SOURCES = "ABSTAINED_INSUFFICIENT_SOURCES"
    ABSTAINED_NEAR_DUPLICATE = "ABSTAINED_NEAR_DUPLICATE"
    ABSTAINED_CITATION_FABRICATION = "ABSTAINED_CITATION_FABRICATION"
    ABSTAINED_MARKET_EXPIRED = "ABSTAINED_MARKET_EXPIRED"


FORECAST_MAX_TOKENS = 1_800
MAX_JSON_FAILURES = 3
MAX_SCHEMA_FAILURES = 2
MAX_CITATION_FAILURES = 2
DEFAULT_TOP_K = 8
MIN_DISTINCT_SOURCES = 3
NEAR_DUPLICATE_COSINE = 0.92
NEAR_DUPLICATE_WINDOW = timedelta(hours=24)
MARKET_CLOSE_BUFFER = timedelta(hours=1)
PROMPT_SEPARATOR_BEGIN = "<<<PROMPT_SEPARATOR_FORECAST_BUNDLE_BEGIN>>>"
PROMPT_SEPARATOR_END = "<<<PROMPT_SEPARATOR_FORECAST_BUNDLE_END>>>"
SNAKE_CASE = re.compile(r"^[a-z0-9]+(?:_[a-z0-9]+)*$")
FORECAST_SCHEMA_KEYS = {
    "probability_yes",
    "confidence_low",
    "confidence_high",
    "headline",
    "reasoning_markdown",
    "uncertainty_notes",
    "topic_hint",
    "citations",
}
FORECAST_CITATION_KEYS = {
    "source_type",
    "source_id",
    "quoted_span",
    "support_label",
}

FORECAST_RESPONSE_SCHEMA: dict[str, Any] = {
    "type": "object",
    "additionalProperties": False,
    "required": [
        "probability_yes",
        "confidence_low",
        "confidence_high",
        "headline",
        "reasoning_markdown",
        "uncertainty_notes",
        "topic_hint",
        "citations",
    ],
    "properties": {
        "probability_yes": {"type": ["number", "null"], "minimum": 0.0, "maximum": 1.0},
        "confidence_low": {"type": "number", "minimum": 0.0, "maximum": 1.0},
        "confidence_high": {"type": "number", "minimum": 0.0, "maximum": 1.0},
        "headline": {"type": "string", "maxLength": 140},
        "reasoning_markdown": {"type": "string", "maxLength": 1800},
        "uncertainty_notes": {"type": "string", "maxLength": 500},
        "topic_hint": {
            "type": "string",
            "maxLength": 40,
            "pattern": r"^[a-z0-9]+(?:_[a-z0-9]+)*$",
        },
        "citations": {
            "type": "array",
            "items": {
                "type": "object",
                "additionalProperties": False,
                "required": [
                    "source_type",
                    "source_id",
                    "quoted_span",
                    "support_label",
                ],
                "properties": {
                    "source_type": {"enum": ["CONCLUSION", "CLAIM"]},
                    "source_id": {"type": "string"},
                    "quoted_span": {"type": "string", "maxLength": 240},
                    "support_label": {"enum": ["DIRECT", "INDIRECT", "CONTRARY"]},
                },
            },
        },
    },
}


@dataclass(frozen=True)
class _CitationValidationHit:
    source_kind: str
    source_id: str
    text: str
    score: float


def retrieve_for_market(store: Any, market: Any, top_k: int = DEFAULT_TOP_K) -> list[Any]:
    """Lazy wrapper so tests that mock retrieval do not import NumPy eagerly."""
    from noosphere.forecasts.retrieval_adapter import retrieve_for_market as _retrieve_for_market

    return _retrieve_for_market(store, market, top_k=top_k)


def embed_text(text: str) -> Any:
    """Embed text using the same local embedding seam as Currents."""
    from noosphere.currents.enrich import embed_text as _embed_text

    return _embed_text(text)


def _prompt_path(name: str) -> Path:
    return Path(__file__).resolve().parent / "_prompts" / name


def _read_system_prompt(name: str) -> str:
    return _prompt_path(name).read_text(encoding="utf-8").strip()


def _utcnow() -> datetime:
    return datetime.now(timezone.utc)


def _as_utc(value: datetime) -> datetime:
    if value.tzinfo is None:
        return value.replace(tzinfo=timezone.utc)
    return value.astimezone(timezone.utc)


def _status_value(value: Any) -> str:
    return str(value.value if hasattr(value, "value") else value)


def _market_expired(market: Any, now: datetime) -> bool:
    if _status_value(getattr(market, "status", "")) != ForecastMarketStatus.OPEN.value:
        return True
    close_time = getattr(market, "close_time", None)
    if close_time is None:
        return False
    if not isinstance(close_time, datetime):
        return True
    return _as_utc(close_time) < now + MARKET_CLOSE_BUFFER


def _distinct_sources(sources: list[Any]) -> list[Any]:
    seen: set[tuple[str, str]] = set()
    distinct: list[Any] = []
    for source in sources:
        key = (
            str(getattr(source, "source_type", "")).upper(),
            str(getattr(source, "source_id", "")),
        )
        if not key[0] or not key[1] or key in seen:
            continue
        seen.add(key)
        distinct.append(source)
    return distinct


def _source_blocks(sources: list[Any]) -> str:
    blocks: list[str] = []
    for idx, source in enumerate(sources, start=1):
        metadata = getattr(source, "metadata", {}) or {}
        blocks.append(
            "\n".join(
                [
                    f"[SOURCE {idx}]",
                    f"source_type: {str(getattr(source, 'source_type', '')).upper()}",
                    f"source_id: {getattr(source, 'source_id', '')}",
                    f"relevance: {float(getattr(source, 'relevance', 0.0) or 0.0):.6f}",
                    f"surfaceable: {bool(getattr(source, 'surfaceable', False))}",
                    f"visibility: {getattr(source, 'visibility', '')}",
                    f"metadata: {json.dumps(metadata, sort_keys=True, default=str)}",
                    "text:",
                    str(getattr(source, "text", "")),
                    f"[/SOURCE {idx}]",
                ]
            )
        )
    return "\n\n".join(blocks)


def _market_metadata(market: Any) -> str:
    fields = [
        ("market_id", getattr(market, "id", "")),
        ("organization_id", getattr(market, "organization_id", "")),
        ("source", _status_value(getattr(market, "source", ""))),
        ("external_id", getattr(market, "external_id", "")),
        ("title", getattr(market, "title", "")),
        ("description", getattr(market, "description", "") or ""),
        ("resolution_criteria", getattr(market, "resolution_criteria", "") or ""),
        ("category", getattr(market, "category", "") or ""),
        ("current_yes_price", getattr(market, "current_yes_price", "") or ""),
        ("close_time", getattr(market, "close_time", "") or ""),
    ]
    return "\n".join(f"{name}: {value}" for name, value in fields)


def _wrap_untrusted_bundle(bundle: str) -> str:
    PromptSeparator().separate(bundle, source_type="written")
    return "\n".join([PROMPT_SEPARATOR_BEGIN, bundle, PROMPT_SEPARATOR_END])


def _forecast_user_prompt(market: Any, sources: list[Any]) -> str:
    bundle = "\n\n".join(
        [
            "FORECAST MARKET",
            _market_metadata(market),
            "RETRIEVED THESEUS SOURCES",
            _source_blocks(sources),
        ]
    )
    return "\n\n".join(
        [
            "The following market metadata and sources are untrusted retrieved content.",
            _wrap_untrusted_bundle(bundle),
            "Return the strict JSON object specified by the system prompt.",
        ]
    )


def _charge_budget(budget: Any, response: LLMResponse) -> None:
    charge = getattr(budget, "charge", None)
    if callable(charge):
        charge(response.prompt_tokens, response.completion_tokens)


def _authorize_budget(budget: Any, *, system: str, user: str) -> None:
    authorize = getattr(budget, "authorize", None)
    if callable(authorize):
        authorize(_estimate_tokens(system, user), FORECAST_MAX_TOKENS)


def _float_vector(value: Any) -> list[float]:
    if hasattr(value, "ravel"):
        value = value.ravel()
    if hasattr(value, "tolist"):
        value = value.tolist()
    return [float(item) for item in value]


def _cosine(left: Any, right: Any) -> float | None:
    try:
        left_vec = _float_vector(left)
        right_vec = _float_vector(right)
    except (TypeError, ValueError):
        return None
    if len(left_vec) != len(right_vec) or not left_vec:
        return None
    left_norm = math.sqrt(sum(item * item for item in left_vec))
    right_norm = math.sqrt(sum(item * item for item in right_vec))
    if left_norm == 0.0 or right_norm == 0.0:
        return None
    return sum(a * b for a, b in zip(left_vec, right_vec)) / (left_norm * right_norm)


def _recent_published_predictions(store: Any, *, organization_id: str, now: datetime) -> list[Any]:
    lister = getattr(store, "list_recent_forecast_predictions", None)
    if not callable(lister):
        return []
    recent = lister(since=now - NEAR_DUPLICATE_WINDOW, limit=200)
    out: list[Any] = []
    for prediction in recent:
        if str(getattr(prediction, "organization_id", "")) != organization_id:
            continue
        if _status_value(getattr(prediction, "status", "")) != ForecastPredictionStatus.PUBLISHED.value:
            continue
        created_at = getattr(prediction, "created_at", None)
        if isinstance(created_at, datetime) and _as_utc(created_at) < now - NEAR_DUPLICATE_WINDOW:
            continue
        out.append(prediction)
    return out


def _is_near_duplicate(store: Any, market: Any, now: datetime) -> bool:
    recent = _recent_published_predictions(
        store,
        organization_id=str(getattr(market, "organization_id", "")),
        now=now,
    )
    if not recent:
        return False

    try:
        market_vec = embed_text(str(getattr(market, "title", "")))
    except Exception:
        return False

    for prediction in recent:
        try:
            prediction_vec = embed_text(str(getattr(prediction, "headline", "")))
        except Exception:
            continue
        similarity = _cosine(market_vec, prediction_vec)
        if similarity is not None and similarity > NEAR_DUPLICATE_COSINE:
            return True
    return False


def _as_float(value: Any, field: str, errors: list[str]) -> float | None:
    if isinstance(value, bool):
        errors.append(f"{field} must be a number")
        return None
    try:
        parsed = float(value)
    except (TypeError, ValueError):
        errors.append(f"{field} must be a number")
        return None
    if not 0.0 <= parsed <= 1.0:
        errors.append(f"{field} must be between 0.0 and 1.0")
        return None
    return parsed


def _text_field(payload: dict[str, Any], field: str, limit: int, errors: list[str]) -> str:
    value = payload.get(field)
    if not isinstance(value, str):
        errors.append(f"{field} must be a string")
        return ""
    if len(value) > limit:
        errors.append(f"{field} must be <= {limit} chars")
    return value.strip()


def _schema_errors(payload: dict[str, Any]) -> list[str]:
    errors: list[str] = []
    missing = sorted(FORECAST_SCHEMA_KEYS - set(payload))
    extra = sorted(set(payload) - FORECAST_SCHEMA_KEYS)
    if missing:
        errors.append("missing required keys: " + ", ".join(missing))
    if extra:
        errors.append("unexpected keys: " + ", ".join(extra))

    probability = _as_float(payload.get("probability_yes"), "probability_yes", errors)
    low = _as_float(payload.get("confidence_low"), "confidence_low", errors)
    high = _as_float(payload.get("confidence_high"), "confidence_high", errors)
    if probability is not None and low is not None and high is not None:
        if not low <= probability <= high:
            errors.append(
                "confidence_high must be >= probability_yes >= confidence_low"
            )
    _text_field(payload, "headline", 140, errors)
    _text_field(payload, "reasoning_markdown", 1800, errors)
    _text_field(payload, "uncertainty_notes", 500, errors)
    topic_hint = _text_field(payload, "topic_hint", 40, errors)
    if topic_hint and SNAKE_CASE.fullmatch(topic_hint) is None:
        errors.append("topic_hint must be snake_case")

    citations = payload.get("citations")
    if not isinstance(citations, list):
        errors.append("citations must be a list")
        return errors
    for idx, citation in enumerate(citations):
        if not isinstance(citation, dict):
            errors.append(f"citation {idx} must be an object")
            continue
        missing_citation = sorted(FORECAST_CITATION_KEYS - set(citation))
        extra_citation = sorted(set(citation) - FORECAST_CITATION_KEYS)
        if missing_citation:
            errors.append(
                f"citation {idx} missing required keys: " + ", ".join(missing_citation)
            )
        if extra_citation:
            errors.append(f"citation {idx} unexpected keys: " + ", ".join(extra_citation))
        if citation.get("source_type") not in {"CONCLUSION", "CLAIM"}:
            errors.append(f"citation {idx} source_type must be CONCLUSION or CLAIM")
        if not isinstance(citation.get("source_id"), str) or not citation.get("source_id"):
            errors.append(f"citation {idx} source_id must be a non-empty string")
        quoted_span = citation.get("quoted_span")
        if not isinstance(quoted_span, str) or not quoted_span:
            errors.append(f"citation {idx} quoted_span must be a non-empty string")
        elif len(quoted_span) > 240:
            errors.append(f"citation {idx} quoted_span must be <= 240 chars")
        if citation.get("support_label") not in {"DIRECT", "INDIRECT", "CONTRARY"}:
            errors.append(f"citation {idx} support_label is invalid")
    return errors


def _is_model_abstention(payload: dict[str, Any]) -> bool:
    return "probability_yes" in payload and payload.get("probability_yes") is None


def _validation_hits(sources: list[Any]) -> list[_CitationValidationHit]:
    return [
        _CitationValidationHit(
            source_kind=str(getattr(source, "source_type", "")).lower(),
            source_id=str(getattr(source, "source_id", "")),
            text=str(getattr(source, "text", "")),
            score=float(getattr(source, "relevance", 0.0) or 0.0),
        )
        for source in sources
    ]


def _citations_for_currents_validator(raw_citations: Any) -> Any:
    if not isinstance(raw_citations, list):
        return raw_citations
    converted: list[Any] = []
    for raw in raw_citations:
        if not isinstance(raw, dict):
            converted.append(raw)
            continue
        converted.append(
            {
                "source_kind": str(raw.get("source_type", "")).lower(),
                "source_id": raw.get("source_id"),
                "quoted_span": raw.get("quoted_span"),
            }
        )
    return converted


def _validate_forecast_citations(
    payload: dict[str, Any],
    sources: list[Any],
) -> tuple[list[dict[str, Any]], list[str]]:
    current_citations = _citations_for_currents_validator(payload.get("citations"))
    normalized, errors = validate_citations(
        current_citations,
        _validation_hits(sources),
        require_any=True,
    )
    if errors:
        return [], errors

    by_key = {
        (
            str(raw.get("source_type", "")).upper(),
            str(raw.get("source_id", "")),
            str(raw.get("quoted_span", "")),
        ): str(raw.get("support_label", ""))
        for raw in payload.get("citations", [])
        if isinstance(raw, dict)
    }
    forecast_citations: list[dict[str, Any]] = []
    for citation in normalized:
        source_type = str(citation["source_kind"]).upper()
        key = (source_type, citation["source_id"], citation["quoted_span"])
        support_label = by_key.get(key, "")
        if support_label not in {"DIRECT", "INDIRECT", "CONTRARY"}:
            errors.append("validated citation is missing a valid support_label")
            continue
        forecast_citations.append(
            {
                "source_type": source_type,
                "source_id": citation["source_id"],
                "quoted_span": citation["quoted_span"],
                "support_label": support_label,
                "retrieval_score": citation["retrieval_score"],
            }
        )

    reasoning = str(payload.get("reasoning_markdown") or "")
    cited_ids = {citation["source_id"] for citation in forecast_citations}
    if cited_ids and not any(source_id in reasoning for source_id in cited_ids):
        errors.append("reasoning_markdown must mention at least one cited source_id")
    return forecast_citations, errors


def _citation_rows(citations: list[dict[str, Any]]) -> list[ForecastCitation]:
    return [
        ForecastCitation(
            prediction_id="",
            source_type=citation["source_type"],
            source_id=citation["source_id"],
            quoted_span=citation["quoted_span"],
            support_label=ForecastSupportLabel(citation["support_label"]),
            retrieval_score=float(citation["retrieval_score"]),
        )
        for citation in citations
    ]


def _trace_principles(citations: list[dict[str, Any]]) -> list[dict[str, Any]]:
    principles: list[dict[str, Any]] = []
    seen: set[str] = set()
    for citation in citations:
        if str(citation.get("source_type", "")).upper() != "CONCLUSION":
            continue
        conclusion_id = str(citation.get("source_id", ""))
        if not conclusion_id or conclusion_id in seen:
            continue
        seen.add(conclusion_id)
        principles.append(
            {
                "conclusionId": conclusion_id,
                "weight": round(float(citation.get("retrieval_score") or 0.0), 6),
                "snippet": str(citation.get("quoted_span") or ""),
            }
        )
    return principles


def _trace_model_output(market: Any, payload: dict[str, Any]) -> dict[str, Any]:
    probability = float(payload["probability_yes"])
    market_yes = getattr(market, "current_yes_price", None)
    market_price = float(market_yes) if market_yes is not None else None
    edge = round(probability - market_price, 6) if market_price is not None else None
    interval_width = float(payload["confidence_high"]) - float(payload["confidence_low"])
    return {
        "side": "YES" if edge is None or edge >= 0 else "NO",
        "edge": edge,
        "confidence": round(max(0.0, min(1.0, 1.0 - interval_width)), 6),
        "rationale": str(payload.get("headline") or "").strip(),
    }


def _trace_gate_results(paper_bet: Any | None) -> list[dict[str, Any]]:
    paper_edge_passed = paper_bet is not None
    return [
        {
            "gateName": "market_open",
            "passed": True,
            "reason": "market was open beyond the forecast close buffer",
        },
        {
            "gateName": "distinct_source_floor",
            "passed": True,
            "reason": f"at least {MIN_DISTINCT_SOURCES} distinct retrieved sources were validated",
        },
        {
            "gateName": "near_duplicate_suppression",
            "passed": True,
            "reason": "no near-duplicate published forecast was found in the recent window",
        },
        {
            "gateName": "citation_integrity",
            "passed": True,
            "reason": "verbatim cited spans matched retrieved source text",
        },
        {
            "gateName": "paper_edge_threshold",
            "passed": paper_edge_passed,
            "reason": (
                "paper fill was recorded"
                if paper_edge_passed
                else "paper fill was skipped because edge or stake threshold did not clear"
            ),
        },
        {
            "gateName": "live_trading_activation",
            "passed": False,
            "reason": "live trading is not activated by the forecast generator path in this round",
        },
    ]


def _write_forecast_trace(
    store: Any,
    *,
    market: Any,
    prediction_id: str,
    payload: dict[str, Any],
    citations: list[dict[str, Any]],
    paper_bet: Any | None,
) -> None:
    writer = getattr(store, "put_forecast_trace", None)
    if not callable(writer):
        return
    writer(
        ForecastTrace(
            prediction_id=prediction_id,
            market_id=str(getattr(market, "id", "")),
            organization_id=str(getattr(market, "organization_id", "")),
            market_title=str(getattr(market, "title", ""))[:280],
            principles_used=_trace_principles(citations),
            model_output=_trace_model_output(market, payload),
            gate_results=_trace_gate_results(paper_bet),
        )
    )


def _decimal_probability(value: Any) -> Decimal:
    return Decimal(str(round(float(value), 6))).quantize(Decimal("0.000001"))


def is_live_authorized(_prediction: ForecastPrediction) -> bool:
    return False


async def generate_forecast(
    store: Any,
    market_id: str,
    *,
    budget: Any,
) -> ForecastOutcome:
    """
    Run retrieve_for_market -> Haiku strict JSON -> verbatim citation checks ->
    write ForecastPrediction + ForecastCitations, or abstain with a precise outcome.
    """
    market = store.get_forecast_market(market_id)
    if market is None:
        raise KeyError(f"unknown forecast market: {market_id}")

    now = _utcnow()
    if _market_expired(market, now):
        return ForecastOutcome.ABSTAINED_MARKET_EXPIRED

    sources = _distinct_sources(retrieve_for_market(store, market, top_k=DEFAULT_TOP_K))
    if len(sources) < MIN_DISTINCT_SOURCES:
        return ForecastOutcome.ABSTAINED_INSUFFICIENT_SOURCES

    if _is_near_duplicate(store, market, now):
        return ForecastOutcome.ABSTAINED_NEAR_DUPLICATE

    base_system = _read_system_prompt("forecast_system.md")
    user_prompt = _forecast_user_prompt(market, sources)
    corrective = ""
    json_failures = 0
    schema_failures = 0
    citation_failures = 0
    total_prompt_tokens = 0
    total_completion_tokens = 0
    model_name = ""
    client = None

    while True:
        system_prompt = base_system + corrective
        try:
            _authorize_budget(budget, system=system_prompt, user=user_prompt)
        except BudgetExhausted:
            return ForecastOutcome.ABSTAINED_BUDGET

        if client is None:
            client = make_client()
        response = await client.complete(
            system=system_prompt,
            user=user_prompt,
            max_tokens=FORECAST_MAX_TOKENS,
            temperature=0.0,
        )
        _charge_budget(budget, response)
        total_prompt_tokens += response.prompt_tokens
        total_completion_tokens += response.completion_tokens
        model_name = response.model or model_name

        try:
            payload = _extract_json_object(response.text)
        except (json.JSONDecodeError, ValueError):
            json_failures += 1
            if json_failures >= MAX_JSON_FAILURES:
                return ForecastOutcome.ABSTAINED_CITATION_FABRICATION
            corrective = (
                "\n\nCorrection: the previous response was not parseable strict JSON. "
                "Return only the JSON object matching the forecast schema."
            )
            continue

        if _is_model_abstention(payload):
            return ForecastOutcome.ABSTAINED_INSUFFICIENT_SOURCES

        schema_errors = _schema_errors(payload)
        if schema_errors:
            schema_failures += 1
            if schema_failures >= MAX_SCHEMA_FAILURES:
                return ForecastOutcome.ABSTAINED_CITATION_FABRICATION
            corrective = (
                "\n\nCorrection: the previous response failed schema validation: "
                + "; ".join(schema_errors[:4])
                + ". In particular, confidence_high must be >= probability_yes >= confidence_low."
            )
            continue

        citations, citation_errors = _validate_forecast_citations(payload, sources)
        if citation_errors:
            citation_failures += 1
            if citation_failures >= MAX_CITATION_FAILURES:
                return ForecastOutcome.ABSTAINED_CITATION_FABRICATION
            corrective = (
                "\n\nCorrection: the previous response failed exact citation validation: "
                + "; ".join(citation_errors[:4])
                + ". Every citation quoted_span must be copied exactly from the cited source text, "
                "and reasoning_markdown must mention at least one cited source_id."
            )
            continue

        prediction = ForecastPrediction(
            market_id=market_id,
            organization_id=getattr(market, "organization_id"),
            probability_yes=_decimal_probability(payload["probability_yes"]),
            confidence_low=_decimal_probability(payload["confidence_low"]),
            confidence_high=_decimal_probability(payload["confidence_high"]),
            headline=str(payload["headline"]).strip()[:140],
            reasoning=str(payload["reasoning_markdown"]).strip(),
            status=ForecastPredictionStatus.PUBLISHED,
            topic_hint=str(payload["topic_hint"]).strip(),
            model_name=model_name or "claude-haiku-4-5",
            prompt_tokens=total_prompt_tokens,
            completion_tokens=total_completion_tokens,
        )
        prediction_id = store.put_forecast_prediction(prediction)
        for row in _citation_rows(citations):
            row.prediction_id = prediction_id
            store.put_forecast_citation(row)
        paper_bet = None
        if not is_live_authorized(prediction):
            paper_bet = await evaluate_and_stake(
                store,
                prediction_id,
                config=PaperBetConfig.from_env(),
                now=now,
            )
        _write_forecast_trace(
            store,
            market=market,
            prediction_id=prediction_id,
            payload=payload,
            citations=citations,
            paper_bet=paper_bet,
        )
        return ForecastOutcome.PUBLISHED

"""Forecast retrieval adapter over the shared Noosphere retrieval path.

The Forecasts pipeline retrieves from the same Noosphere index as Currents,
but its inputs and stricter surfacing rules differ. Centralizing this wrapper
means a future change to Currents-side retrieval cannot silently weaken
Forecasts-side surfacing -- the filter is enforced here, post-retrieval, where
Forecasts owns it.
"""

from __future__ import annotations

from dataclasses import dataclass
from datetime import date, datetime, timedelta, timezone
from typing import Any, Literal

from noosphere.currents.retrieval_adapter import retrieve_for_event
from noosphere.models import Claim, Conclusion, ForecastMarket
from noosphere.observability import get_logger

log = get_logger(__name__)

SourceType = Literal["CONCLUSION", "CLAIM"]
Visibility = Literal["PUBLIC", "FOUNDER", "INTERNAL"]

DEFAULT_TOP_K = 8
RETRIEVAL_OVERSAMPLE = 4
MAX_CANDIDATES = 40
MAX_SOURCE_AGE = timedelta(days=18 * 31)
MMR_LAMBDA = 0.7


@dataclass(frozen=True)
class RetrievedSource:
    source_type: SourceType
    source_id: str
    text: str
    relevance: float
    surfaceable: bool
    visibility: Visibility
    metadata: dict[str, Any]


@dataclass(frozen=True)
class _MarketRetrievalEvent:
    text: str
    topic_hint: str | None = None
    embedding: bytes | None = None


def _truncate(value: Any, limit: int) -> str:
    return str(value or "").strip()[:limit]


def _clean(value: Any) -> str:
    return str(value or "").strip()


def build_query_from_market(market: ForecastMarket) -> str:
    """
    Compose a single query string the embedding-side retriever can use.

    Recipe:
      title
      "\n\n"
      description (truncated to 600 chars)
      "\n\n"
      "Resolution criteria: " + resolutionCriteria (truncated to 400 chars)
      "\n\n"
      "Category: " + category
    """

    title = _clean(getattr(market, "title", ""))
    description = _truncate(getattr(market, "description", ""), 600)
    resolution_criteria = _truncate(
        getattr(
            market,
            "resolution_criteria",
            getattr(market, "resolutionCriteria", ""),
        ),
        400,
    )
    category = _clean(getattr(market, "category", ""))
    return (
        f"{title}\n\n"
        f"{description}\n\n"
        f"Resolution criteria: {resolution_criteria}\n\n"
        f"Category: {category}"
    )


def retrieve_for_market(
    store: Any,
    market: ForecastMarket,
    *,
    top_k: int = DEFAULT_TOP_K,
) -> list[RetrievedSource]:
    """
    Wrap Currents retrieval for Forecast markets.

    Filter rules:
      - drop sources with `visibility != PUBLIC` UNLESS source.surfaceable is True
      - drop revoked conclusions
      - drop sources older than 18 months unless `is_load_bearing` is True
      - apply MMR (maximal marginal relevance) with lambda=0.7 to diversify
      - return at most top_k sources

    On error: never raise. Return [] and emit a `forecasts.retrieval.error`
    structured log. The generator treats [] as INSUFFICIENT_SOURCES.
    """

    if top_k <= 0:
        return []

    query = build_query_from_market(market)
    event = _MarketRetrievalEvent(
        text=query,
        topic_hint=getattr(market, "category", None),
    )
    retrieval_k = min(max(top_k * RETRIEVAL_OVERSAMPLE, top_k), MAX_CANDIDATES)

    try:
        hits = retrieve_for_event(store, event, top_k=retrieval_k)
        sources: list[RetrievedSource] = []
        seen: set[tuple[str, str]] = set()
        for hit in hits:
            source = _source_from_hit(store, hit)
            if source is None:
                continue
            key = (source.source_type, source.source_id)
            if key in seen:
                continue
            seen.add(key)
            sources.append(source)
        return _mmr_select(sources, query, top_k=top_k)
    except Exception as exc:  # pragma: no cover - exercised via tests.
        log.warning(
            "forecasts.retrieval.error",
            market_id=getattr(market, "id", ""),
            error=str(exc),
        )
        return []


def _source_from_hit(store: Any, hit: Any) -> RetrievedSource | None:
    source_kind = str(getattr(hit, "source_kind", "")).lower()
    source_id = str(getattr(hit, "source_id", ""))
    if source_kind == "conclusion":
        conclusion = _get_conclusion(store, source_id)
        if conclusion is None or _is_revoked(conclusion):
            return None
        return _to_retrieved_source(
            source_type="CONCLUSION",
            source_id=source_id,
            text=str(getattr(hit, "text", getattr(conclusion, "text", ""))),
            relevance=float(getattr(hit, "score", 0.0)),
            source=conclusion,
        )
    if source_kind == "claim":
        claim = store.get_claim(source_id) if hasattr(store, "get_claim") else None
        if claim is None:
            return None
        return _to_retrieved_source(
            source_type="CLAIM",
            source_id=source_id,
            text=str(getattr(hit, "text", getattr(claim, "text", ""))),
            relevance=float(getattr(hit, "score", 0.0)),
            source=claim,
        )
    return None


def _get_conclusion(store: Any, conclusion_id: str) -> Conclusion | None:
    if hasattr(store, "get_conclusion"):
        conclusion = store.get_conclusion(conclusion_id)
        if conclusion is not None:
            return conclusion
    if hasattr(store, "list_conclusions"):
        for conclusion in store.list_conclusions():
            if str(getattr(conclusion, "id", "")) == conclusion_id:
                return conclusion
    return None


def _to_retrieved_source(
    *,
    source_type: SourceType,
    source_id: str,
    text: str,
    relevance: float,
    source: Conclusion | Claim,
) -> RetrievedSource | None:
    visibility = _visibility_for(source, source_type)
    surfaceable = _surfaceable_for(source, visibility)
    if visibility != "PUBLIC" and not surfaceable:
        return None
    if _is_stale(source):
        return None
    return RetrievedSource(
        source_type=source_type,
        source_id=source_id,
        text=text,
        relevance=max(0.0, min(1.0, relevance)),
        surfaceable=surfaceable,
        visibility=visibility,
        metadata=_metadata_for(source, source_type),
    )


def _field(source: Any, name: str, default: Any = None) -> Any:
    if hasattr(source, name):
        return getattr(source, name)
    extra = getattr(source, "model_extra", None)
    if isinstance(extra, dict) and name in extra:
        return extra[name]
    pydantic_extra = getattr(source, "__pydantic_extra__", None)
    if isinstance(pydantic_extra, dict) and name in pydantic_extra:
        return pydantic_extra[name]
    if isinstance(source, dict):
        return source.get(name, default)
    return default


def _literal_name(value: Any) -> str:
    if hasattr(value, "name"):
        return str(value.name).upper()
    if hasattr(value, "value"):
        return str(value.value).upper()
    return str(value or "").upper()


def _visibility_for(source: Any, source_type: SourceType) -> Visibility:
    explicit = _literal_name(_field(source, "visibility", ""))
    if explicit in {"PUBLIC", "FOUNDER", "INTERNAL"}:
        return explicit  # type: ignore[return-value]

    if source_type == "CLAIM":
        origin = _literal_name(_field(source, "claim_origin", ""))
        if origin in {"FOUNDER", "INTERNAL"}:
            return origin  # type: ignore[return-value]
        return "PUBLIC"

    confidence_tier = _literal_name(_field(source, "confidence_tier", ""))
    if confidence_tier == "FOUNDER":
        return "FOUNDER"
    return "PUBLIC"


def _surfaceable_for(source: Any, visibility: Visibility) -> bool:
    raw = _field(source, "surfaceable", None)
    if raw is not None:
        return bool(raw)
    public_safe = _field(source, "public_safe", None)
    if public_safe is not None:
        return bool(public_safe)
    return visibility == "PUBLIC"


def _is_revoked(source: Any) -> bool:
    if bool(_field(source, "is_revoked", False)):
        return True
    if _field(source, "revoked_at", None) is not None:
        return True
    if _field(source, "revokedAt", None) is not None:
        return True
    return False


def _is_stale(source: Any) -> bool:
    if bool(_field(source, "is_load_bearing", False)):
        return False
    created = _source_datetime(source)
    if created is None:
        return False
    return _utc_now() - created > MAX_SOURCE_AGE


def _source_datetime(source: Any) -> datetime | None:
    for field_name in (
        "created_at",
        "createdAt",
        "episode_date",
        "updated_at",
        "updatedAt",
    ):
        value = _field(source, field_name, None)
        if isinstance(value, datetime):
            return _as_utc(value)
        if isinstance(value, date):
            return datetime(value.year, value.month, value.day, tzinfo=timezone.utc)
    return None


def _as_utc(value: datetime) -> datetime:
    if value.tzinfo is None:
        return value.replace(tzinfo=timezone.utc)
    return value.astimezone(timezone.utc)


def _utc_now() -> datetime:
    return datetime.now(timezone.utc)


def _metadata_for(source: Any, source_type: SourceType) -> dict[str, Any]:
    metadata: dict[str, Any] = {
        "source_type": source_type,
    }
    for field_name in (
        "disciplines",
        "confidence",
        "confidence_tier",
        "principles_used",
        "claims_used",
        "claim_origin",
        "source_id",
        "chunk_id",
        "evidence_pointers",
        "is_load_bearing",
    ):
        value = _field(source, field_name, None)
        if value is None:
            continue
        metadata[field_name] = _serializable(value)
    return metadata


def _serializable(value: Any) -> Any:
    if isinstance(value, list):
        return [_serializable(item) for item in value]
    if hasattr(value, "value"):
        return value.value
    if isinstance(value, (str, int, float, bool, dict)):
        return value
    return str(value)


def _mmr_select(
    sources: list[RetrievedSource],
    query: str,
    *,
    top_k: int,
) -> list[RetrievedSource]:
    if len(sources) <= top_k:
        return sorted(sources, key=_rank_key)[:top_k]

    selected: list[RetrievedSource] = []
    remaining = sorted(sources, key=_rank_key)
    query_terms = _terms(query)
    while remaining and len(selected) < top_k:
        best = max(
            remaining,
            key=lambda source: _mmr_score(source, selected, query_terms),
        )
        selected.append(best)
        remaining.remove(best)
    return selected


def _mmr_score(
    source: RetrievedSource,
    selected: list[RetrievedSource],
    query_terms: set[str],
) -> float:
    query_similarity = max(source.relevance, _jaccard(_terms(source.text), query_terms))
    if not selected:
        return query_similarity
    diversity_penalty = max(
        _jaccard(_terms(source.text), _terms(chosen.text)) for chosen in selected
    )
    return MMR_LAMBDA * query_similarity - (1.0 - MMR_LAMBDA) * diversity_penalty


def _rank_key(source: RetrievedSource) -> tuple[float, int, str]:
    return (
        -source.relevance,
        0 if source.source_type == "CONCLUSION" else 1,
        source.source_id,
    )


def _terms(text: str) -> set[str]:
    return {
        token
        for token in "".join(ch.lower() if ch.isalnum() else " " for ch in text).split()
        if len(token) >= 3
    }


def _jaccard(left: set[str], right: set[str]) -> float:
    if not left or not right:
        return 0.0
    return len(left & right) / len(left | right)

"""Paper-only staking and settlement for Forecasts."""

from __future__ import annotations

import os
from dataclasses import dataclass
from datetime import UTC, datetime
from decimal import ROUND_HALF_UP, Decimal, InvalidOperation
from typing import Any

from sqlmodel import select

from noosphere.models import (
    ForecastBet,
    ForecastBetMode,
    ForecastBetSide,
    ForecastBetStatus,
    ForecastExchange,
    ForecastMarket,
    ForecastOutcome,
    ForecastPortfolioState,
    ForecastPrediction,
)

MONEY = Decimal("0.01")
PRICE = Decimal("0.000001")
DEFAULT_INITIAL_BALANCE = Decimal("10000.00")


@dataclass(frozen=True)
class PaperBetConfig:
    edge_threshold: float = 0.05
    kelly_fraction: float = 0.25
    max_stake_usd: float = 50.0
    initial_balance_usd: float = 10_000.0
    organization_id: str = ""

    @classmethod
    def from_env(cls) -> PaperBetConfig:
        return cls(
            edge_threshold=_env_float(
                "FORECASTS_PAPER_EDGE_THRESHOLD",
                cls.edge_threshold,
            ),
            kelly_fraction=_env_float(
                "FORECASTS_PAPER_KELLY_FRACTION",
                cls.kelly_fraction,
            ),
            max_stake_usd=_env_float(
                "FORECASTS_PAPER_MAX_STAKE_USD",
                cls.max_stake_usd,
            ),
            initial_balance_usd=_env_float(
                "FORECASTS_PAPER_INITIAL_BALANCE_USD",
                cls.initial_balance_usd,
            ),
            organization_id=os.getenv("FORECASTS_INGEST_ORG_ID", "").strip(),
        )


async def evaluate_and_stake(
    store: Any,
    prediction_id: str,
    *,
    config: PaperBetConfig,
    now: datetime | None = None,
) -> ForecastBet | None:
    """
    Evaluate a published prediction against the mirrored market price and
    persist a paper fill when the edge clears the configured threshold.
    """

    timestamp = _aware_utc(now or _utcnow())
    with store.session() as session:
        prediction = session.get(ForecastPrediction, prediction_id)
        if prediction is None:
            raise KeyError(f"unknown forecast prediction: {prediction_id}")
        market = session.get(ForecastMarket, prediction.market_id)
        if market is None:
            raise KeyError(f"unknown forecast market: {prediction.market_id}")

        probability_yes = _decimal_or_none(prediction.probability_yes)
        market_yes_price = _decimal_or_none(market.current_yes_price)
        if probability_yes is None or market_yes_price is None:
            return None
        if not Decimal("0") <= probability_yes <= Decimal("1"):
            return None
        if not Decimal("0") < market_yes_price < Decimal("1"):
            return None

        edge = probability_yes - market_yes_price
        if abs(edge) < _decimal_from_float(config.edge_threshold):
            return None

        side = ForecastBetSide.YES if edge > 0 else ForecastBetSide.NO
        market_side_price = _market_price_for_side(market, side)
        if market_side_price is None or not (
            Decimal("0") < market_side_price < Decimal("1")
        ):
            return None

        model_side_probability = (
            probability_yes
            if side == ForecastBetSide.YES
            else Decimal("1") - probability_yes
        )
        stake = _stake_usd(
            model_probability=model_side_probability,
            market_price=market_side_price,
            paper_balance=_paper_state(
                session,
                organization_id=_organization_id(prediction, market, config),
                config=config,
                now=timestamp,
            ).paper_balance_usd,
            config=config,
        )
        if stake < Decimal("1.00"):
            return None

        organization_id = _organization_id(prediction, market, config)
        state = _paper_state(
            session,
            organization_id=organization_id,
            config=config,
            now=timestamp,
        )
        if state.paper_balance_usd < stake:
            stake = _money(state.paper_balance_usd)
        if stake < Decimal("1.00"):
            return None

        bet = ForecastBet(
            prediction_id=prediction.id,
            organization_id=organization_id,
            mode=ForecastBetMode.PAPER,
            exchange=ForecastExchange(_enum_value(market.source)),
            side=side,
            stake_usd=stake,
            entry_price=_price(market_side_price),
            status=ForecastBetStatus.FILLED,
            created_at=timestamp,
        )
        state.paper_balance_usd = _money(state.paper_balance_usd - stake)
        state.updated_at = timestamp
        session.add(state)
        session.add(bet)
        session.commit()
        session.refresh(bet)
        return bet


async def settle_paper_bets_for_market(store: Any, market_id: str) -> int:
    """
    Settle every open paper fill for a resolved market and apply the payoff to
    the organization's paper balance. A second call is a no-op.
    """

    timestamp = _utcnow()
    with store.session() as session:
        market = session.get(ForecastMarket, market_id)
        if market is None:
            raise KeyError(f"unknown forecast market: {market_id}")
        outcome = _outcome_or_none(market.resolved_outcome)
        if outcome is None:
            return 0

        rows = list(
            session.exec(
                select(ForecastBet, ForecastPrediction)
                .join(
                    ForecastPrediction,
                    ForecastBet.prediction_id == ForecastPrediction.id,
                )
                .where(ForecastPrediction.market_id == market_id)
                .where(ForecastBet.mode == ForecastBetMode.PAPER.value)
                .where(ForecastBet.status == ForecastBetStatus.FILLED.value)
                .order_by(ForecastBet.created_at)
            ).all()
        )
        if not rows:
            return 0

        payoffs_by_org: dict[str, Decimal] = {}
        for bet, prediction in rows:
            _ = prediction
            payoff, exit_price = _settlement_payoff(bet, outcome)
            bet.status = ForecastBetStatus.SETTLED
            bet.exit_price = exit_price
            bet.settlement_pnl_usd = _money(payoff - bet.stake_usd)
            bet.settled_at = timestamp
            session.add(bet)
            payoffs_by_org[bet.organization_id] = (
                payoffs_by_org.get(bet.organization_id, Decimal("0.00")) + payoff
            )

        for organization_id, payoff in payoffs_by_org.items():
            state = _paper_state(
                session,
                organization_id=organization_id,
                config=PaperBetConfig(),
                now=timestamp,
            )
            state.paper_balance_usd = _money(state.paper_balance_usd + payoff)
            state.updated_at = timestamp
            session.add(state)

        session.commit()
        return len(rows)


def _stake_usd(
    *,
    model_probability: Decimal,
    market_price: Decimal,
    paper_balance: Decimal,
    config: PaperBetConfig,
) -> Decimal:
    if config.kelly_fraction <= 0 or config.max_stake_usd <= 0:
        return Decimal("0.00")
    b = (Decimal("1") - market_price) / market_price
    q = Decimal("1") - model_probability
    raw_fraction = ((b * model_probability) - q) / b
    fraction = min(max(raw_fraction, Decimal("0")), Decimal("1"))
    stake = fraction * _decimal_from_float(config.kelly_fraction) * paper_balance
    stake = min(stake, _decimal_from_float(config.max_stake_usd))
    return _money(stake)


def _settlement_payoff(
    bet: ForecastBet,
    outcome: ForecastOutcome,
) -> tuple[Decimal, Decimal]:
    if outcome == ForecastOutcome.CANCELLED:
        return _money(bet.stake_usd), _price(bet.entry_price)

    side_won = (
        (outcome == ForecastOutcome.YES and bet.side == ForecastBetSide.YES)
        or (outcome == ForecastOutcome.NO and bet.side == ForecastBetSide.NO)
    )
    if not side_won:
        return Decimal("0.00"), Decimal("0.000000")
    return _money(bet.stake_usd / bet.entry_price), Decimal("1.000000")


def _paper_state(
    session: Any,
    *,
    organization_id: str,
    config: PaperBetConfig,
    now: datetime,
) -> ForecastPortfolioState:
    state = session.exec(
        select(ForecastPortfolioState).where(
            ForecastPortfolioState.organization_id == organization_id
        )
    ).first()
    if state is not None:
        return state

    initial_balance = _decimal_from_float(config.initial_balance_usd)
    if initial_balance <= Decimal("0"):
        initial_balance = DEFAULT_INITIAL_BALANCE
    state = ForecastPortfolioState(
        organization_id=organization_id,
        paper_balance_usd=_money(initial_balance),
        live_balance_usd=None,
        daily_loss_usd=Decimal("0.00"),
        daily_loss_reset_at=now,
        kill_switch_engaged=False,
        kill_switch_reason=None,
        updated_at=now,
    )
    session.add(state)
    session.flush()
    return state


def _market_price_for_side(
    market: ForecastMarket,
    side: ForecastBetSide,
) -> Decimal | None:
    yes_price = _decimal_or_none(market.current_yes_price)
    if side == ForecastBetSide.YES:
        return yes_price
    no_price = _decimal_or_none(market.current_no_price)
    if no_price is not None:
        return no_price
    if yes_price is None:
        return None
    return Decimal("1") - yes_price


def _organization_id(
    prediction: ForecastPrediction,
    market: ForecastMarket,
    config: PaperBetConfig,
) -> str:
    return (
        str(prediction.organization_id or "").strip()
        or str(market.organization_id or "").strip()
        or config.organization_id
    )


def _outcome_or_none(value: Any) -> ForecastOutcome | None:
    if value is None:
        return None
    try:
        outcome = ForecastOutcome(_enum_value(value))
    except ValueError:
        return None
    if outcome not in {
        ForecastOutcome.YES,
        ForecastOutcome.NO,
        ForecastOutcome.CANCELLED,
    }:
        return None
    return outcome


def _enum_value(value: Any) -> str:
    return str(value.value if hasattr(value, "value") else value)


def _env_float(key: str, default: float) -> float:
    raw = os.getenv(key)
    if raw is None or not raw.strip():
        return default
    return float(raw.strip())


def _decimal_from_float(value: float) -> Decimal:
    return Decimal(str(value))


def _decimal_or_none(value: Any) -> Decimal | None:
    if value is None:
        return None
    try:
        return Decimal(str(value))
    except (InvalidOperation, ValueError, TypeError):
        return None


def _money(value: Decimal) -> Decimal:
    return Decimal(value).quantize(MONEY, rounding=ROUND_HALF_UP)


def _price(value: Decimal) -> Decimal:
    return Decimal(value).quantize(PRICE, rounding=ROUND_HALF_UP)


def _utcnow() -> datetime:
    return datetime.now(UTC)


def _aware_utc(value: datetime) -> datetime:
    if value.tzinfo is None:
        return value.replace(tzinfo=UTC)
    return value.astimezone(UTC)

"""Persistent Forecasts scheduler status for readiness checks."""

from __future__ import annotations

import json
import os
import tempfile
from dataclasses import asdict, is_dataclass
from datetime import datetime, timezone
from decimal import Decimal
from pathlib import Path
from typing import Any


STATUS_FILENAME = "forecasts_status.json"
DEFAULT_STATUS_PATH = Path("/var/lib/theseus") / STATUS_FILENAME


def status_path_from_env() -> Path:
    explicit = os.environ.get("FORECASTS_STATUS_PATH", "").strip()
    if explicit:
        return Path(explicit)
    legacy = os.environ.get("FORECASTS_RESOLUTION_STATUS_PATH", "").strip()
    if legacy:
        return Path(legacy)
    data_dir = os.environ.get("NOOSPHERE_DATA_DIR", "").strip()
    if data_dir:
        return Path(data_dir) / STATUS_FILENAME
    return DEFAULT_STATUS_PATH


def utc_now_iso() -> str:
    return datetime.now(timezone.utc).replace(microsecond=0).isoformat().replace(
        "+00:00",
        "Z",
    )


def parse_utc_iso(value: object) -> datetime | None:
    if not isinstance(value, str) or not value.strip():
        return None
    raw = value.strip()
    if raw.endswith("Z"):
        raw = f"{raw[:-1]}+00:00"
    try:
        parsed = datetime.fromisoformat(raw)
    except ValueError:
        return None
    if parsed.tzinfo is None:
        return parsed.replace(tzinfo=timezone.utc)
    return parsed.astimezone(timezone.utc)


def _payload(report: Any) -> dict[str, Any]:
    if is_dataclass(report):
        return asdict(report)
    if isinstance(report, dict):
        return dict(report)
    raise TypeError(f"unsupported status report type: {type(report).__name__}")


def _json_default(value: Any) -> Any:
    if isinstance(value, datetime):
        return value.astimezone(timezone.utc).replace(microsecond=0).isoformat().replace(
            "+00:00",
            "Z",
        )
    if isinstance(value, Decimal):
        return float(value)
    raise TypeError(f"object of type {type(value).__name__} is not JSON serializable")


def write_status(report: Any, path: Path | None = None) -> Path:
    target = Path(path) if path is not None else status_path_from_env()
    target.parent.mkdir(parents=True, exist_ok=True)
    payload = _payload(report)

    fd, tmp_name = tempfile.mkstemp(
        prefix=f".{target.name}.",
        suffix=".tmp",
        dir=str(target.parent),
        text=True,
    )
    tmp_path = Path(tmp_name)
    try:
        with os.fdopen(fd, "w", encoding="utf-8") as fh:
            json.dump(payload, fh, indent=2, sort_keys=True, default=_json_default)
            fh.write("\n")
            fh.flush()
            os.fsync(fh.fileno())
        os.replace(tmp_path, target)
    finally:
        if tmp_path.exists():
            tmp_path.unlink()
    return target


def read_status(path: Path | None = None) -> dict[str, Any]:
    target = Path(path) if path is not None else status_path_from_env()
    return json.loads(target.read_text(encoding="utf-8"))

